import{_ as e,o as a,c as r,a1 as l}from"./chunks/framework.BX4nIuL2.js";const x=JSON.parse('{"title":"FAB EDU","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/Fab/fabkids.md","filePath":"courses/fab-course/doc/Fab/fabkids.md"}'),d={name:"courses/fab-course/doc/Fab/fabkids.md"};function n(i,t,s,c,o,h){return a(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="fab-edu" tabindex="-1">FAB EDU <a class="header-anchor" href="#fab-edu" aria-label="Permalink to &quot;FAB EDU&quot;">​</a></h1><p>基于MIT fabLab 的课程内容，为不同年龄的学生提供系列创意课程，激发同学的创新能力，通过实践来刺激想象力，自我表达想法。初步掌握跨学科的支持和能力（创新探索，视觉传达，材料实验，2D设计，3D设计，3D打印，激光切割，电路控制，互联网通信，物联网交互等）。主要分为初级课程（3-6年级入门），中级课程（主要是6-9级），pro课程（初高中），工程课程（大学）四个级别。</p><table tabindex="0"><thead><tr><th>主题</th><th style="text-align:center;">初级</th><th style="text-align:center;">中级</th><th style="text-align:center;">pro课程</th><th style="text-align:center;">设计工程</th></tr></thead><tbody><tr><td>创新思维</td><td style="text-align:center;">如何发现问题</td><td style="text-align:center;">如何用设计解决问题</td><td style="text-align:center;">如何制造万物</td><td style="text-align:center;">Done</td></tr><tr><td>理论基础</td><td style="text-align:center;">/</td><td style="text-align:center;">问题/设计/结构/电子/程序组合</td><td style="text-align:center;">问题/设计/结构/电子/程序组合/物联网</td><td style="text-align:center;">wait</td></tr><tr><td>电路应用</td><td style="text-align:center;">1.纸电路<br>2.Arduino</td><td style="text-align:center;">Arduino<br>2.电路计算</td><td style="text-align:center;">1.Arduino<br>2.IOT<br> 3电路计算</td><td style="text-align:center;">wait</td></tr><tr><td>程序</td><td style="text-align:center;">thinkerCAD代码块编程</td><td style="text-align:center;">Arduino IDE</td><td style="text-align:center;">1.Arduino<br>2.IOT<br> 3.vcode</td><td style="text-align:center;">wait</td></tr><tr><td>材料</td><td style="text-align:center;">1.金属<br>2.塑料<br> 3.木<br>4.气体<br>5.液体</td><td style="text-align:center;">1.热塑水晶<br>2.硅胶<br> 3.树脂<br>4.琥珀<br>5.蜡烛</td><td style="text-align:center;">复合材料</td><td style="text-align:center;">wait</td></tr><tr><td>机械设计</td><td style="text-align:center;">thinker CAD 结构设计</td><td style="text-align:center;">fusion360</td><td style="text-align:center;">fusion 360</td><td style="text-align:center;">Done</td></tr><tr><td>机械加工</td><td style="text-align:center;">1.3D打印<br>2.激光切割</td><td style="text-align:center;">1.3D打印<br>2.激光切割<br> 3.CNC雕刻机</td><td style="text-align:center;">1.3D打印<br>2.激光切割<br> 3.CNC雕刻机</td><td style="text-align:center;">wait</td></tr><tr><td>调试</td><td style="text-align:center;">装配与调试</td><td style="text-align:center;">装配与调试</td><td style="text-align:center;">装配与调试</td><td style="text-align:center;">装配与调试</td></tr><tr><td>输出</td><td style="text-align:center;">展示</td><td style="text-align:center;">展示</td><td style="text-align:center;">展示</td><td style="text-align:center;">展示</td></tr></tbody></table><h2 id="_1-初级课程" tabindex="-1">1.初级课程 <a class="header-anchor" href="#_1-初级课程" aria-label="Permalink to &quot;1.初级课程&quot;">​</a></h2><h4 id="_1-1针对群体" tabindex="-1">1.1针对群体 <a class="header-anchor" href="#_1-1针对群体" aria-label="Permalink to &quot;1.1针对群体&quot;">​</a></h4><p>小学生3-6年级零基础，目标让学生有初步的创新开发能力，通过实践案例增加对理工科内容的兴趣，增加对学习的热情。为后续的创新性探索打好基础。</p><h4 id="_1-2课程内容" tabindex="-1">1.2课程内容 <a class="header-anchor" href="#_1-2课程内容" aria-label="Permalink to &quot;1.2课程内容&quot;">​</a></h4><ol><li><p>体验课：3d打印冰墩墩（其他IP热点也可以），</p><ul><li>内容： <ul><li>亲子互动，选择3D数据（冰墩墩），在软件上进行参数调试，数据保存至sd卡并在3D打印机上打印模型；（60分钟）</li><li>fab与创新分享（40 分钟）</li><li>后续课程介绍（10-20分钟）</li></ul></li><li>参与人数：5-6组；</li><li>产出：参与者在现场体验流程，现场或者课后择机来现场取模；</li><li>费用：待定</li><li>时间：2小时（做3-4次，有更多流量来体验）</li></ul></li><li><p>实际课程内容</p></li></ol><table tabindex="0"><thead><tr><th>主题</th><th style="text-align:center;">学习内容</th><th style="text-align:center;">作用</th><th style="text-align:center;">材料</th></tr></thead><tbody><tr><td>我的家</td><td style="text-align:center;">1.通过纸电路来连接电源，输入设备（开关）、输出设备(LED,喇叭，电机等）；<br>2.通过折纸展现房子里的控制、声、光、电机</td><td style="text-align:center;">1.掌握电路的概念 <br>2.掌握手工工具如何使用<br>3.了解控制的基础概念</td><td style="text-align:center;">导电胶带，卡纸，开关，LED，喇叭，电池，电阻等，剪刀</td></tr><tr><td>妈妈的礼物</td><td style="text-align:center;">1.网上数据平台</td><td style="text-align:center;">/</td><td style="text-align:center;">/</td></tr></tbody></table><p>| 钢铁侠的面具 |纸电路|/| /| /| | 玩具熊 |纸电路|/| /| /| | 妈妈的礼物 |纸电路|/| /| /| | 心中的车 |纸电路|/| /| /|</p><h4 id="_1-3-宣传资料" tabindex="-1">1.3 宣传资料 <a class="header-anchor" href="#_1-3-宣传资料" aria-label="Permalink to &quot;1.3 宣传资料&quot;">​</a></h4><h4 id="_1-4-其他" tabindex="-1">1.4 其他 <a class="header-anchor" href="#_1-4-其他" aria-label="Permalink to &quot;1.4 其他&quot;">​</a></h4><ul><li>费用</li><li>物料支出</li></ul><h2 id="_2-中级课程" tabindex="-1">2.中级课程 <a class="header-anchor" href="#_2-中级课程" aria-label="Permalink to &quot;2.中级课程&quot;">​</a></h2><h2 id="_3-pro课程" tabindex="-1">3.pro课程 <a class="header-anchor" href="#_3-pro课程" aria-label="Permalink to &quot;3.pro课程&quot;">​</a></h2><h2 id="_4-设计工程" tabindex="-1">4.设计工程 <a class="header-anchor" href="#_4-设计工程" aria-label="Permalink to &quot;4.设计工程&quot;">​</a></h2><p>参考nexmaker</p>',17)])])}const y=e(d,[["render",n]]);export{x as __pageData,y as default};
